const express = require('express');
const { Client } = require('@elastic/elasticsearch');
const app = express();

app.use(express.json());

const client = new Client({
  node: process.env.ELASTICSEARCH_NODE || 'http://localhost:9200',
  auth: {
    username: process.env.ELASTICSEARCH_USERNAME || 'elastic',
    password: process.env.ELASTICSEARCH_PASSWORD || 'changeme'
  }
});

// Validate index name to prevent directory traversal and injection
function validateIndexName(indexName) {
  if (!indexName || typeof indexName !== 'string') {
    throw new Error('Invalid index name');
  }
  
  // Check for forbidden characters and patterns
  if (indexName.includes('..') || indexName.includes('\\') || indexName.includes('/')) {
    throw new Error('Invalid index name: contains forbidden characters');
  }
  
  // Allow only alphanumeric, dots, hyphens, and underscores
  if (!/^[a-zA-Z0-9._-]+$/.test(indexName)) {
    throw new Error('Invalid index name: contains invalid characters');
  }
  
  // Prevent empty or overly long names
  if (indexName.length === 0 || indexName.length > 255) {
    throw new Error('Invalid index name length');
  }
  
  return true;
}

// Validate query DSL to prevent malicious input
function validateQueryDSL(query) {
  if (!query || typeof query !== 'object') {
    throw new Error('Invalid query DSL');
  }
  
  // Check for potentially dangerous operations
  const dangerousOperations = ['script', 'aggs', 'size', 'from', 'sort'];
  for (const op of dangerousOperations) {
    if (query[op] && typeof query[op] === 'object') {
      // Basic validation - in production, implement more comprehensive checks
      if (Object.keys(query[op]).length > 100) {
        throw new Error('Query contains too many operations');
      }
    }
  }
  
  return true;
}

app.post('/search/:index', async (req, res) => {
  try {
    const { index } = req.params;
    const { query } = req.body;
    
    // Validate index name
    validateIndexName(index);
    
    // Validate query DSL
    validateQueryDSL(query);
    
    // Execute search with validated inputs
    const result = await client.search({
      index: index,
      body: query
    });
    
    res.json(result.body);
  } catch (error) {
    console.error('Search error:', error);
    if (error.message.includes('Invalid index name') || error.message.includes('Invalid query DSL')) {
      return res.status(400).json({ error: error.message });
    }
    res.status(500).json({ error: 'Internal server error' });
  }
});

